    configuracion_json : `[{"uid": "3f379b31-4ccb-44e1-88b5-341b12b89e58", "url": "${config.app.backendUrl}api/system/usuario-cargo", "edit": true, "name": "derivacionNaN", "type": "derivacion", "label": "Derivacion NaN", "query": null, "active": false, "visible": true, "disabled": false, "readonly": false, "required": false, "ariaLabel": null, "subCampos": ["de", "via", "para", "referencia"], "typeInput": "derivacion", "customClass": null, "placeholder": null, "validations": [], "autocomplete": null, "customStyles": null, "defaultValue": {}, "designColumn": "col-12", "configuracion": {"configDe": {"visible": true, "multiple": true, "required": true, "cargoActual": true, "dependencia": ""}, "configVia": {"visible": false, "multiple": true, "required": true, "cargoActual": false, "dependencia": ""}, "configPara": {"visible": false, "multiple": true, "required": true, "cargoActual": false, "dependencia": ""}}, "ariaLabelledBy": null, "optionsDependencias": [{"label": "Dependendencia lineal", "value": "idDepenenciaLinea"}, {"label": "Dependendencia funcional", "value": "idDependenciaFuncional"}, {"label": "Dependendencia formulario", "value": "idDependenciaFormulario"}, {"label": "Dependendencia POAI", "value": "idDependenciaPoai"}, {"label": "Aprueba viaje", "value": "idApruebaViaje"}, {"label": "Elabora Memorandum Viaje", "value": "idElaboraMemorandumViaje"}]}, {"uid": "3979d92b-613e-4bd8-99dc-c817822cfec7", "edit": true, "name": "title1446", "type": "title", "label": "VISTOS Y CONSIDERANDO:", "active": false, "visible": true, "disabled": false, "readonly": false, "required": false, "ariaLabel": null, "typeInput": "subtitle", "customClass": null, "placeholder": null, "validations": [], "autocomplete": null, "customStyles": null, "designColumn": "col-12", "ariaLabelledBy": null}, {"uid": "13c2fc43-b238-450c-b248-6c16e29ae7c2", "edit": true, "name": "vistos_considerado", "type": "editor", "label": "", "value": "Que, el numeral 2, del artículo 9 de la Constitución Política del Estado, establece que son fines y funciones esenciales del Estado 2. garantizar el bienestar, el desarrollo, la seguridad y la protección e igual dignidad de las personas, las naciones, los pueblos y las comunidades, y fomentar el respeto mutuo y el diálogo intracultural, intercultural y plurilingüe.<br /> Que, el parágrafo I, del artículo 35 del Texto Constitucional, establece que El Estado en todos sus niveles, protegerá el derecho a la salud, promoviendo políticas públicas orientadas a mejorar la calidad de vida, el bienestar colectivo y el acceso gratuito de la población a los servicios de salud. <br /> Que, el numeral 1, parágrafo I, del artículo 46 de la referida Norma Suprema, señala que toda persona tiene derecho al trabajo digno, con seguridad industrial, higiene y salud ocupacional, sin discriminación, y con remuneración o salario justo, equitativo y satisfactorio que le asegure para sí y su familia una existencia digna. Por su parte el Parágrafo II de la misma norma constitucional dispone que el Estado protegerá el ejercicio del trabajo en todas sus formas. <br /> Que, el Decreto Supremo N° 4404, de 28 de noviembre de 2020, tiene por objeto establecer protocolos y medidas de bioseguridad, medidas para el Sistema Nacional de Salud, actividades económicas, jornada laboral y otras, para proteger la salud y la vida de la población ante la pandemia del COVID- 19, en la etapa de recuperación y preparación ante un eventual incremento de casos.", "active": false, "visible": true, "disabled": false, "readonly": false, "required": false, "ariaLabel": null, "typeInput": "text", "customClass": null, "placeholder": null, "validations": [], "autocomplete": null, "customStyles": null, "designColumn": "col-12", "ariaLabelledBy": null}, {"uid": "16ebd2e8-9799-462c-b516-1f5b3001a213", "edit": true, "name": "title1447", "type": "title", "label": "POR TANTO:", "active": false, "visible": true, "disabled": false, "readonly": false, "required": false, "ariaLabel": null, "typeInput": "subtitle", "customClass": null, "placeholder": null, "validations": [], "autocomplete": null, "customStyles": null, "designColumn": "col-12", "ariaLabelledBy": null}, {"uid": "81b759f4-e8c5-4d61-880c-9a21c8e394cd", "edit": true, "name": "por_tanto", "type": "editor", "label": "", "value": "El Ministro de Justicia y Transparencia Institucional, en ejercicio de las atribuciones establecidas en los numerales 3 y 4 del parágrafo I del Artículo 175 de la Constitución Política del Estado Plurinacional y los numerales 17 y 22 del parágrafo I del Artículo 14 del Decreto Supremo N° 29894 de 7 de febrero de 2009.", "active": false, "visible": true, "disabled": false, "readonly": false, "required": false, "ariaLabel": null, "typeInput": "text", "customClass": null, "placeholder": null, "validations": [], "autocomplete": null, "customStyles": null, "designColumn": "col-12", "ariaLabelledBy": null}, {"uid": "6edcd793-ec55-4b29-a540-049a6f07b9bc", "edit": true, "name": "title1448", "type": "title", "label": "RESUELVE :", "active": false, "visible": true, "disabled": false, "readonly": false, "required": false, "ariaLabel": null, "typeInput": "subtitle", "customClass": null, "placeholder": null, "validations": [], "autocomplete": null, "customStyles": null, "designColumn": "col-12", "ariaLabelledBy": null}, {"uid": "ea40068f-57ea-4167-b6ae-48f84bb4bb3a", "edit": true, "name": "resuelve", "type": "editor", "label": "", "value": "PRIMERO.- APROBAR el PROTOCOLO ESPECÍFICO DE BIOSEGURIDAD DEL MINISTERIO DE JUSTICIA Y TRASPARENCIA INSTITUCIONAL que tiene por objetivo reducir el riesgo de contagio de SARS-CoV2 en el ambiente laboral, durante el desempeño de tareas cotidianas del personal del Ministerio de Justicia y Transparencia Institucional cuyo anexo forma parte indivisible de la Presente Resolución Ministerial, el cual es de cumplimiento obligatorio para los servidores públicos, personal eventual y consultores dependientes del Ministerio de Justicia y Transparencia Institucional. <br /> SEGUNDO.- La Dirección General de Asuntos Administrativos a través de la Unidad Administrativa y Recursos Humanos de esta Cartera de Estado, debe generar mecanismos de implementación para la difusión, aplicación y control del PROTOCOLO ESPECÍFICO DE BIOSEGURIDAD DEL MINISTERIO DE JUSTICIA Y TRASPARENCIA INSTITUCIONAL, siendo responsables de su ejecución y el estricto cumplimiento.", "active": false, "visible": true, "disabled": false, "readonly": false, "required": false, "ariaLabel": null, "typeInput": "text", "customClass": null, "placeholder": null, "validations": [], "autocomplete": null, "customStyles": null, "designColumn": "col-12", "ariaLabelledBy": null}, {"uid": "166b09b0-3fd3-43fa-aa8b-36a3b593d3fa", "edit": true, "name": "title1449", "type": "title", "label": "<b>Regístrese, comuníquese, cúmplase y archívese.</b>", "active": false, "visible": true, "disabled": false, "readonly": false, "required": false, "ariaLabel": null, "typeInput": "normal", "customClass": null, "placeholder": null, "validations": [], "autocomplete": null, "customStyles": null, "designColumn": "col-12", "ariaLabelledBy": null}]`,
