    configuracion_json : `[{"uid":"00a3102e-1787-4502-9921-2b7e72aa0996","url":"${config.app.backendUrl}api/system/usuario-cargo","edit":true,"name":"derivacionNaN","type":"derivacion","label":"Derivacion NaN","query":null,"active":false,"visible":true,"disabled":false,"readonly":false,"required":false,"ariaLabel":null,"subCampos":["de","via","para","referencia"],"typeInput":"derivacion","customClass":null,"placeholder":null,"validations":[],"autocomplete":null,"customStyles":null,"defaultValue":{},"designColumn":"col-12","configuracion":{"configDe":{"visible":true,"multiple":true,"cargoActual":true,"dependencia":"","required":true},"configVia":{"visible":false,"multiple":false,"cargoActual":false,"dependencia":"","required":true},"configPara":{"visible":true,"multiple":false,"cargoActual":false,"dependencia":"","required":true}},"ariaLabelledBy":null,"optionsDependencias":[{"label":"Dependendencia lineal","value":"idDepenenciaLinea"},{"label":"Dependendencia funcional","value":"idDependenciaFuncional"},{"label":"Dependendencia formulario","value":"idDependenciaFormulario"},{"label":"Dependendencia POAI","value":"idDependenciaPoai"},{"label":"Aprueba viaje","value":"idApruebaViaje"},{"label":"Elabora Memorandum Viaje","value":"idElaboraMemorandumViaje"}]},{"uid":"32970cac-7d58-48e6-97ba-24f547003162","edit":true,"name":"contenido","type":"editor","label":"","value":"De mi mayor consideración:<div><br></div><div>Mediante la presente, adjunto y presento documentos (facturas, pases a bordo y otros) originales de respaldo de acuerdo al siguiente detalle:</div><div><br></div><div>para los fines consiguientes&nbsp;</div>","active":false,"visible":true,"disabled":false,"readonly":false,"required":false,"ariaLabel":null,"typeInput":"text","customClass":null,"placeholder":null,"validations":[],"autocomplete":null,"customStyles":null,"defaultValue":"","designColumn":"col-12","ariaLabelledBy":null},{"uid":"5f60f4aa-8e6c-4961-a760-73600f2d7609","url":"${config.app.backendUrl}public/upload","edit":true,"name":"upload2","type":"upload","label":"adjuntos","active":false,"visible":true,"disabled":false,"mergePdf":true,"readonly":false,"required":false,"ariaLabel":null,"maxlength":"5","typeInput":"pdf","customClass":null,"placeholder":null,"validations":[],"autocomplete":null,"customStyles":null,"defaultValue":[],"designColumn":"col-12","ariaLabelledBy":null}]`,
